# Check dependencies for Xunit.Combinatorial 2.0.24 and Xunit.StaFact 3.0.13
curl -s 'https://api.nuget.org/v3/registration5-gz-semver2/xunit.combinatorial/index.json' | python3 -c "
import sys,json
data=json.load(sys.stdin)
for page in data['items']:
    for item in page.get('items',[]):
        v=item['catalogEntry']['version']
        if v=='2.0.24':
            deps=item['catalogEntry'].get('dependencyGroups',[])
            print(f'Xunit.Combinatorial {v}:')
            for dg in deps:
                print(f'  TFM: {dg.get(\"targetFramework\",\"any\")}')
                for d in dg.get('dependencies',[]):
                    print(f'    {d[\"id\"]} {d.get(\"range\",\"\")}')
" 2>/dev/null

